// ParseInteraction — parse Discord slash command interaction
const body = $input.item.json.body || $input.item.json;

// Type 1 = PING (Discord validation)
if (body.type === 1) {
  return [{ json: { isPing: true, application_id: body.application_id } }];
}

// Type 2 = APPLICATION_COMMAND (slash command)
if (body.type === 2) {
  const data    = body.data || {};
  const user    = body.member?.user || body.user || {};
  const options = data.options || [];
  const guild_id = body.guild_id;

  const optionValues = {};
  for (const opt of options) {
    optionValues[opt.name] = opt.value;
  }

  return [{
    json: {
      isPing: false,
      application_id: body.application_id,
      commandName: data.name || 'unknown',
      userId: user.id,
      username: user.username || user.global_name || 'Unknown',
      guild_id,
      interaction_id: body.id,
      interaction_token: body.token,
      options: optionValues
    }
  }];
}

return [{ json: { isPing: false, application_id: null, error: 'Unknown interaction type' } }];

// Merge person_id from identity resolver into the interaction payload
const resolverOutput = $input.item.json;
const interaction = $('ParseInteraction').item.json;

return [{
  json: {
    ...interaction,
    person_id: resolverOutput.person_id,
    display_name: resolverOutput.display_name
  }
}];

// Format /status response
const rows = $input.all().map(i => i.json).filter(r => r.platform);
const displayName = rows[0]?.display_name || 'Unknown';
const linked = rows.map(r => `${r.platform} (${r.username || r.platform_user_id})`).join(', ');

return [{
  json: {
    discordResponse: {
      type: 4,
      data: {
        content: `**Identity:** ${displayName}\n**Linked platforms:** ${linked || 'none'}`,
        flags: 64
