parameters.query:
SELECT COALESCE(
  (SELECT pi.person_id::text FROM platform_identities pi
   WHERE pi.platform = $1 AND pi.platform_user_id = $2 LIMIT 1),
  NULL
) as person_id;

SELECT
  COALESCE(
    (SELECT pi.person_id::text FROM platform_identities pi WHERE pi.platform = 'discord' AND pi.platform_user_id = $1 LIMIT 1),
    NULL
  ) as discord_person_id,
  COALESCE(
    (SELECT pi.person_id::text FROM platform_identities pi WHERE pi.platform = 'telegram' AND pi.platform_user_id = $2 LIMIT 1),
    NULL
  ) as telegram_person_id;

