const interaction = $('Evaluate Role (link)').item.json;
const discord_id = interaction.options.discord_id;
const telegram_id = interaction.options.telegram_id;

const row = $input.item.json;
const discordPersonId = row.discord_person_id || null;
const telegramPersonId = row.telegram_person_id || null;

const needsMerge = discordPersonId && telegramPersonId && discordPersonId !== telegramPersonId;
const alreadyLinked = discordPersonId && telegramPersonId && discordPersonId === telegramPersonId;

// Discord person is winner; Telegram is loser
return [{
  json: {
    discord_id,
    telegram_id,
    interaction_id: interaction.interaction_id,
    interaction_token: interaction.interaction_token,
    winner_person_id: discordPersonId,
    loser_person_id: telegramPersonId,
    needs_merge: needsMerge,
    already_linked: alreadyLinked,
    discord_missing: !discordPersonId,
    telegram_missing: !telegramPersonId
  }
}];

const parsed = $('ParseInteraction').first().json;
const identity = $input.first().json;
return [{ json: {
  commandName: parsed.commandName,
  userId: parsed.userId,
  username: parsed.username,
  options: parsed.options || {},
  interaction_token: parsed.interaction_token,
  application_id: parsed.application_id,
  interaction_id: parsed.interaction_id,
  guild_id: parsed.guild_id,
  person_id: identity.person_id,
  display_name: identity.display_name || parsed.username
} }];

const rows = $input.all().map(i => i.json);
const ctx = $('Merge person_id (memory)').first().json;
const realRows = rows.filter(r => r.core_id !== null && r.core_id !== undefined);
if (realRows.length === 0) {
  return [{ json: { ...ctx, reply: "I don't have any stored memories about you yet." } }];
}
const lines = realRows.map(r => {
  const lock = r.locked ? ' 🔒' : '';
  const status = r.status === 'provisional' ? ' *(provisional)*' : '';
  // Strip timestamp suffix from user.stated.NNNN -> user.stated
  const keyLabel = r.key_label.replace(/\.\d{10,}$/, '');
  // Avoid double-prefix if claim_text already starts with key_label
  const prefix = keyLabel + ': ';
  const text = r.claim_text.startsWith(prefix) || r.claim_text.startsWith(r.key_label + ': ')
    ? r.claim_text.replace(r.key_label + ': ', prefix)
    : prefix + r.claim_text;
  return '• ' + text + lock + status;
});
return [{ json: { ...ctx, reply: '**What I remember about you:**\n' + lines.join('\n') } }];

const ctx = $('Merge person_id (memory)').first().json;
const found = $('Pin Search').first().json;
return [{ json: { ...ctx, reply: 'Locked: **' + found.claim_text + '** — I won\'t overwrite this.' } }];

